# DiskStation Monitor - Full frontend swap to prototype
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\FULLSWAP.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Swapping frontend to prototype..." -ForegroundColor Cyan

# frontend/public/synology-monitor.html
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend\public\synology-monitor.html"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/public/synology-monitor.html" -ForegroundColor Green

# frontend/vite.config.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend\vite.config.ts"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/vite.config.ts" -ForegroundColor Green

# netlify.toml
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "netlify.toml"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote netlify.toml" -ForegroundColor Green

git add -A
git commit -m "feat: full frontend swap - static public/ deploy, prototype UX"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n Done! Auth: https://dsm.4thandbailey.com/dsm-auth.html" -ForegroundColor Green
    Write-Host "   Dashboard: https://dsm.4thandbailey.com/synology-monitor.html" -ForegroundColor Cyan
} else {
    Write-Host "`n Push failed." -ForegroundColor Red
}
